import{_ as e,o as a,c as s,a2 as i}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Sovereign — Development Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"development-workflow.md","filePath":"development-workflow.md"}'),d={name:"development-workflow.md"};function n(o,t,r,l,c,h){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="sovereign-—-development-workflow" tabindex="-1">Sovereign — Development Workflow <a class="header-anchor" href="#sovereign-—-development-workflow" aria-label="Permalink to &quot;Sovereign — Development Workflow&quot;">​</a></h1><p>How tasks are planned, started, implemented, and closed out. Designed for agentic execution with human oversight.</p><hr><h2 id="three-layer-information-architecture" tabindex="-1">Three-layer information architecture <a class="header-anchor" href="#three-layer-information-architecture" aria-label="Permalink to &quot;Three-layer information architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CLAUDE.md / AGENTS.md      ← agent-specific adapter; conventions only (no task pointer)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─▶ docs/roadmap.md    ← chronological index; one row per PR; canonical status</span></span>
<span class="line"><span>            │</span></span>
<span class="line"><span>            └─▶ docs/epics/&lt;epic&gt;.md   ← full task detail: Goal, Deliverables,</span></span>
<span class="line"><span>                                           SRS reference, Review checklist</span></span></code></pre></div><p>Each layer has a single job:</p><table tabindex="0"><thead><tr><th>File</th><th>Job</th><th>What agents read it for</th></tr></thead><tbody><tr><td><code>CLAUDE.md</code> / <code>AGENTS.md</code></td><td>Agent-specific conventions</td><td>How to work; architectural rules; commit/PR conventions</td></tr><tr><td><code>docs/roadmap.md</code></td><td>Version-ordered task index</td><td>Which tasks exist, their status, which epic file has the detail</td></tr><tr><td><code>docs/epics/&lt;file&gt;.md</code></td><td>Full task spec</td><td>Goal, deliverables, checklist for the active task</td></tr><tr><td><code>CURRENT_TASK.md</code></td><td>Active task scratch (transient)</td><td>Everything needed mid-task without re-navigating</td></tr></tbody></table><blockquote><p><strong>Multi-agent note:</strong> The <code>⏳ Next</code> pointer previously in <code>CLAUDE.md</code> has been removed. The developer assigns the next task explicitly at session start. See <code>docs/multi-agent.md</code> for the full model.</p></blockquote><hr><h2 id="epic-structure" tabindex="-1">Epic structure <a class="header-anchor" href="#epic-structure" aria-label="Permalink to &quot;Epic structure&quot;">​</a></h2><p>Work is organized into domain epics. Each task has a <strong>stable epic task ID</strong> (<code>&lt;epic&gt;.&lt;seq&gt;</code>) that can be cited in PRs, RFCs, and commits independently of roadmap version numbers.</p><table tabindex="0"><thead><tr><th>ID</th><th>Epic file</th><th>Domain</th></tr></thead><tbody><tr><td>0</td><td><code>infrastructure.md</code></td><td>Monorepo, Docker, CI, testing pipeline, deployment</td></tr><tr><td>1</td><td><code>users-auth.md</code></td><td>Auth server, sessions, MFA, roles, capabilities</td></tr><tr><td>2</td><td><code>platform-shell.md</code></td><td>Runtime host, middleware, shell modes, SDK bridge</td></tr><tr><td>3</td><td><code>plugins-runtime.md</code></td><td>Manifest, generate script, SDK contract, plugin lifecycle</td></tr><tr><td>4</td><td><code>notification-center.md</code></td><td>In-app inbox, toasts, web push, pub/sub</td></tr><tr><td>5</td><td><code>activity-logs.md</code></td><td>Audit trail for user and admin actions</td></tr><tr><td>6</td><td><code>analytics.md</code></td><td>Self-hosted privacy-first usage analytics</td></tr><tr><td>7</td><td><code>monetization.md</code></td><td>Ed25519 entitlement tokens, billing, payments</td></tr><tr><td>8</td><td><code>data-sovereignty.md</code></td><td>Backup/restore, portability, per-plugin DB, deletion</td></tr><tr><td>9</td><td><code>design-system.md</code></td><td>Design system, white-labeling, instance identity, i18n</td></tr><tr><td>10</td><td><code>accessibility.md</code></td><td>WCAG 2.1 AA, a11y lint, plugin a11y contract</td></tr><tr><td>11</td><td><code>i18n.md</code></td><td>Internationalization infrastructure and translations</td></tr><tr><td>12</td><td><code>example-plugins.md</code></td><td>Starter templates and capability-demo plugins</td></tr><tr><td>13</td><td><code>plugin-console.md</code></td><td>Admin console plugin</td></tr><tr><td>14</td><td><code>plugin-accounts.md</code></td><td>Account plugin</td></tr><tr><td>15</td><td><code>plugin-launcher.md</code></td><td>Launcher plugin</td></tr><tr><td>16</td><td><code>docs.md</code></td><td>VitePress docs site and project landing page</td></tr><tr><td>17</td><td><code>desktop.md</code></td><td>Native desktop shell</td></tr><tr><td>18</td><td><code>sovereign-harness.md</code></td><td>AI assistant and orchestration layer</td></tr><tr><td>19</td><td><code>sovereign-council.md</code></td><td>Multi-model deliberation workspace</td></tr><tr><td>20</td><td><code>mobile.md</code></td><td>Native mobile shell</td></tr><tr><td>21</td><td><code>sovereign-wallet.md</code></td><td>Encrypted wallet platform plugin</td></tr><tr><td>22</td><td><code>core-assistant.md</code></td><td>Runtime assistant and local inference</td></tr><tr><td>23</td><td><code>p2p-chat.md</code></td><td>Companion P2P chat, identity, transport, and E2EE</td></tr></tbody></table><p>The epic index is <code>docs/epics/README.md</code> in the repository planning docs.</p><h3 id="stable-ids-vs-volatile-slots" tabindex="-1">Stable IDs vs volatile slots <a class="header-anchor" href="#stable-ids-vs-volatile-slots" aria-label="Permalink to &quot;Stable IDs vs volatile slots&quot;">​</a></h3><p><strong>Epic task IDs are permanent.</strong> Once an ID like <code>9.9</code> is assigned it never changes — it is the stable identifier for that unit of work. Use epic task IDs in doc cross-references, RFC <code>incorporated_into_plan</code> fields, and task dependency lists.</p><p><strong>Roadmap slot versions are volatile.</strong> A slot like <code>0.9.2</code> reflects current priority ordering and may shift when tasks are reprioritized (e.g. <code>0.9.5 → 0.9.1</code>). Always look up the live slot from <code>docs/roadmap.md</code> rather than copying it from another doc; include roadmap slots only where the shipping order matters (upgrade notes, version maps).</p><hr><h2 id="task-lifecycle" tabindex="-1">Task lifecycle <a class="header-anchor" href="#task-lifecycle" aria-label="Permalink to &quot;Task lifecycle&quot;">​</a></h2><h3 id="starting-a-task" tabindex="-1">Starting a task <a class="header-anchor" href="#starting-a-task" aria-label="Permalink to &quot;Starting a task&quot;">​</a></h3><p>Run <code>/sv-task-start</code>. The skill:</p><ol><li>The developer specifies the task (epic task ID or description) — there is no <code>⏳ Next</code> pointer. See <code>docs/multi-agent.md</code>.</li><li>Confirms <code>main</code> is clean and pulls latest.</li><li>Looks up the epic file via <code>docs/epics/README.md</code>, then greps for the task heading to extract the full task block (Goal → Deliverables → SRS reference → Review checklist).</li><li>Writes <strong><code>CURRENT_TASK.md</code></strong> in the repo root — the full task spec in one file, no further navigation needed.</li><li>Reads the relevant RFC if one is referenced.</li><li>Prints a summary and creates the feature branch.</li></ol><h3 id="during-implementation" tabindex="-1">During implementation <a class="header-anchor" href="#during-implementation" aria-label="Permalink to &quot;During implementation&quot;">​</a></h3><p>Read <code>CURRENT_TASK.md</code> for task context at any point. It contains everything: goal, deliverables, and the review checklist. No need to re-open the epic file or roadmap mid-task.</p><h3 id="completing-a-task" tabindex="-1">Completing a task <a class="header-anchor" href="#completing-a-task" aria-label="Permalink to &quot;Completing a task&quot;">​</a></h3><p>Run <code>/sv-task-complete</code>. The skill orchestrates three role agents, two of which run in parallel:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[parallel]</span></span>
<span class="line"><span>  /sv-verify       — runs all checks, returns structured pass/fail summary</span></span>
<span class="line"><span>  /sv-update-task-docs— updates roadmap row + epic heading, deletes CURRENT_TASK.md</span></span>
<span class="line"><span>[sequential, after both complete]</span></span>
<span class="line"><span>  /sv-security-check— only if diff touches auth/middleware/CSP/SDK paths</span></span>
<span class="line"><span>  main agent       — version bumps + PR description</span></span>
<span class="line"><span>  /sv-create-pr    — creates the GitHub PR as a draft when requested</span></span></code></pre></div><p><strong><code>/sv-verify</code></strong> reads <code>CURRENT_TASK.md</code>, runs <code>format:check</code>, <code>lint</code>, <code>typecheck</code>, <code>test</code> (and docs-parity if relevant), and returns a summary table — not raw output. Failures block the PR draft.</p><p><strong><code>/sv-update-task-docs</code></strong> reads <code>CURRENT_TASK.md</code> for metadata, marks the roadmap row ✅, updates the matching epic task heading to ✅, and deletes <code>CURRENT_TASK.md</code>. It does not append completion entries to <code>CLAUDE.md</code> or <code>AGENTS.md</code> — <code>docs/roadmap.md</code> and the task&#39;s epic heading are the canonical completion markers.</p><p><strong><code>/sv-security-check</code></strong> (conditional) reviews the diff against the hard architectural rules in <code>CLAUDE.md</code> — redirect codes, CSP construction, cookie clearing, session config, <code>NEXT_PUBLIC_*</code> usage. Violations block the PR draft.</p><p><strong><code>/sv-create-pr</code></strong> creates the GitHub pull request. Agent-created PRs are always opened as <strong>draft</strong> PRs first with <code>gh pr create --draft</code>, even when the human simply says &quot;create the PR&quot;. Mark a PR ready for review only after explicit human instruction.</p><hr><h2 id="status-tracking" tabindex="-1">Status tracking <a class="header-anchor" href="#status-tracking" aria-label="Permalink to &quot;Status tracking&quot;">​</a></h2><p>Status lives in exactly two places:</p><table tabindex="0"><thead><tr><th>Location</th><th>What it tracks</th></tr></thead><tbody><tr><td><code>docs/roadmap.md</code> row Status cell</td><td>✅ / ⏳ / 📋 per task — the canonical record</td></tr><tr><td>Open PRs</td><td>Which tasks are currently in flight</td></tr></tbody></table><p><strong>Epic file headings (<code>#### ✅ X.Y — …</code>) are updated when a task completes.</strong> To close a task, mark both the roadmap row and the matching <code>docs/epics/&lt;file&gt;.md</code> task heading ✅ in the same PR.</p><hr><h2 id="current-task-md-—-the-active-task-file" tabindex="-1"><code>CURRENT_TASK.md</code> — the active task file <a class="header-anchor" href="#current-task-md-—-the-active-task-file" aria-label="Permalink to &quot;\`CURRENT_TASK.md\` — the active task file&quot;">​</a></h2><p><code>CURRENT_TASK.md</code> is a transient file written by <code>/sv-task-start</code> and deleted by <code>/sv-task-complete</code>. It is never committed.</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Current Task</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Epic task:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 9.9</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Roadmap version:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 0.9.1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Branch:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> feat/email-templates</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Epic file:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> docs/epics/design-system.md</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">#### ⏳ 9.9 — Email template system + White-labeling Phase 2 …</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Goal:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> …</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Deliverables:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> …</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**SRS reference:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> …</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Review checklist:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> …</span></span></code></pre></div><p>Any agent or sub-agent working on the current task should read this file first. It is the single source of truth for what is being built right now.</p><p>If <code>CURRENT_TASK.md</code> does not exist, no task is in progress — run <code>/sv-task-start</code> to begin one.</p><hr><h2 id="cross-references-between-epics" tabindex="-1">Cross-references between epics <a class="header-anchor" href="#cross-references-between-epics" aria-label="Permalink to &quot;Cross-references between epics&quot;">​</a></h2><p>Some tasks belong primarily to one epic but are relevant to another (e.g. per-plugin database is in Plugins Runtime but is also a Data Sovereignty concern). The secondary epic contains a short cross-reference block instead of duplicating the full entry:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">#### ✅ 8.3 — Per-plugin database</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">&gt; Full entry: </span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**[</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">3.13</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">]**</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;"> in [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">plugins-runtime.md</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">](</span><span style="--shiki-light:#22863A;--shiki-light-text-decoration:underline;--shiki-dark:#85E89D;--shiki-dark-text-decoration:underline;">plugins-runtime.md</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">) — Per-plugin database.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">&gt; This task provisions the isolated storage layer that keeps plugin data physically separate</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">&gt; from the platform DB — a key component of data sovereignty.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span></code></pre></div><p>The <code>**[3.13]**</code> notation is the stable epic task ID. It survives task renames because it references the ID, not a markdown anchor.</p><hr><h2 id="version-identifiers" tabindex="-1">Version identifiers <a class="header-anchor" href="#version-identifiers" aria-label="Permalink to &quot;Version identifiers&quot;">​</a></h2><p>When a PR bumps a package version, use the release identifier as the version-bump commit subject and as the release tag:</p><table tabindex="0"><thead><tr><th>Versioned target</th><th>Commit subject / tag</th></tr></thead><tbody><tr><td>Root <code>package.json</code></td><td><code>vX.Y.Z</code></td></tr><tr><td><code>packages/ui</code></td><td><code>ui-vX.Y.Z</code></td></tr><tr><td><code>apps/docs</code></td><td><code>docs-vX.Y.Z</code></td></tr><tr><td><code>packages/sdk</code></td><td><code>sdk-vX.Y.Z</code></td></tr><tr><td>Any other package/app/plugin tag</td><td><code>&lt;slug&gt;-vX.Y.Z</code></td></tr></tbody></table><p>Use the package slug from the workspace path unless a public release workflow defines a more specific slug.</p><hr><h2 id="role-agents" tabindex="-1">Role agents <a class="header-anchor" href="#role-agents" aria-label="Permalink to &quot;Role agents&quot;">​</a></h2><p>Four focused skills cover the non-implementation phases of a task. Each needs only <code>CURRENT_TASK.md</code> plus its own skill file — no full project orientation required.</p><table tabindex="0"><thead><tr><th>Skill</th><th>Trigger</th><th>What it does</th></tr></thead><tbody><tr><td><code>/sv-verify</code></td><td>Parallel with <code>/sv-update-task-docs</code> at task-complete</td><td>Runs all checks, returns structured pass/fail table</td></tr><tr><td><code>/sv-update-task-docs</code></td><td>Parallel with <code>/sv-verify</code> at task-complete</td><td>Marks roadmap and epic heading ✅, deletes CURRENT_TASK.md</td></tr><tr><td><code>/sv-security-check</code></td><td>Conditional — when diff touches auth/middleware/CSP/SDK</td><td>Reviews diff against hard architectural rules, blocks PR on violation</td></tr><tr><td><code>/sv-task-start</code></td><td>Session start</td><td>Writes CURRENT_TASK.md, creates branch</td></tr></tbody></table><p>Each agent is briefed with <code>CURRENT_TASK.md</code> (~50 lines) rather than the full project context. The Verifier and Docs Updater run in parallel, so the task-complete wall-clock is bounded by whichever takes longer (verification, ~30–60s) rather than their sum.</p><hr><h2 id="quick-reference-for-agents" tabindex="-1">Quick reference for agents <a class="header-anchor" href="#quick-reference-for-agents" aria-label="Permalink to &quot;Quick reference for agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>I need to know…</th><th>Read…</th></tr></thead><tbody><tr><td>What task is next</td><td>Ask the developer; check <code>docs/roadmap.md</code> for pending tasks</td></tr><tr><td>Full spec for the current task</td><td><code>CURRENT_TASK.md</code></td></tr><tr><td>Full spec for any task by epic ID</td><td><code>docs/epics/&lt;file&gt;.md</code> — grep for <code>^#### .*&lt;id&gt;</code></td></tr><tr><td>All tasks in a domain</td><td><code>docs/epics/&lt;file&gt;.md</code></td></tr><tr><td>Roadmap version number for a task</td><td><code>docs/roadmap.md</code></td></tr><tr><td>Which epic a roadmap task belongs to</td><td><code>docs/roadmap.md</code> → Epic task column</td></tr><tr><td>Epic file for a given epic ID</td><td><code>docs/epics/README.md</code></td></tr><tr><td>Project conventions and hard rules</td><td><code>CLAUDE.md</code></td></tr><tr><td>Security rules to check against</td><td><code>CLAUDE.md</code> → &quot;Hard architectural rules&quot; section</td></tr></tbody></table>`,59)])])}const g=e(d,[["render",n]]);export{k as __pageData,g as default};
